// Hand-authored shared test harness for the transcendence (novel) commands.
// No "Generated by CLI Printing Press" header so regen-merge keeps it.

package cli

import (
	"bytes"
	"encoding/json"
	"path/filepath"
	"testing"

	"tactical-rmm-pp-cli/internal/store"
)

// novelTestEnv isolates the local store under a temp HOME so defaultDBPath
// resolves to a per-test data.db. Returns the resolved db path.
func novelTestEnv(t *testing.T) string {
	t.Helper()
	home := t.TempDir()
	t.Setenv("HOME", home)
	return filepath.Join(home, ".local", "share", "tactical-rmm-cli", "data.db")
}

// seedResource opens (creating) the store at dbPath and upserts one row into
// the shared resources table under resourceType.
func seedResource(t *testing.T, dbPath, resourceType, id string, data string) {
	t.Helper()
	s, err := store.Open(dbPath)
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	defer s.Close()
	if err := s.Upsert(resourceType, id, json.RawMessage(data)); err != nil {
		t.Fatalf("upsert %s/%s: %v", resourceType, id, err)
	}
}

// runNovel executes the full root command tree with the given args, isolating
// the store under a temp HOME. Returns (stdout, stderr, error). It always
// passes --json so the output is machine-parseable.
func runNovel(t *testing.T, args ...string) (string, string, error) {
	t.Helper()
	var flags rootFlags
	root := newRootCmd(&flags)
	var out, errBuf bytes.Buffer
	root.SetOut(&out)
	root.SetErr(&errBuf)
	root.SetArgs(append([]string{"--json"}, args...))
	err := root.Execute()
	return out.String(), errBuf.String(), err
}

// assertJSON fails the test unless s decodes as JSON into v.
func assertJSON(t *testing.T, s string, v any) {
	t.Helper()
	if err := json.Unmarshal([]byte(s), v); err != nil {
		t.Fatalf("output is not valid JSON: %v\n---\n%s", err, s)
	}
}
